var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"카린 양!","JPN":"カリンさん！","ENG":"Karin!","TWN":"卡琳小姐！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"아...... 시영 씨.","JPN":"あ……シノンさん。","ENG":"Ah... Shiyoung.","TWN":"啊……時雨小姐。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"수고했어요...... 이제 다 끝났습니다.","JPN":"お疲れ様でした……これですべておしまいです。","ENG":"Good job... It's over now.","TWN":"辛苦妳了……現在都結束了。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"한 번 차원 통로가 안정화 된 이상 이제 돌이킬 방법은 없습니다.","JPN":"一度次元間通路ができた以上、引き返すことはできません。","ENG":"Now that the dimensional passageway has settled into place, there's no turning back.","TWN":"一旦次元通道被固定，就再也沒有辦法扭轉了。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"곧 이쪽 세상으로 <color=#ffd34c>네피림</color>이 건너올 거에요.","JPN":"もうすぐこちら側に、<color=#ffd34c>ネフィリム</color>がやってくるでしょう。","ENG":"Soon, the <color=#ffd34c>Nephil</color> will come over here.","TWN":"<color=#ffd34c>諾菲力</color>馬上就要到這個世界來了。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"시영 씨는 어디든 도망가도 괜찮습니다. 임무는 끝났어요.","JPN":"シノンさんはどこかへ逃げてもらって構いません。任務は終了です。","ENG":"Shiyoung, you can run. Your job here is done.","TWN":"時雨小姐逃去其他地方也沒關係。任務已經結束了。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"도망? 카린 양은요?","JPN":"逃げるって？　カリンさんは？","ENG":"I can run? What about you, Karin?","TWN":"逃跑？卡琳小姐呢？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"......저는 이곳에 남습니다.","JPN":"……私はここに残ります。","ENG":"I'm staying.","TWN":"……我要留在這裡。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"이곳이 아무것도 없는 무저갱이었다면 미련 없이 도망쳤겠지만......","JPN":"ここが何も存在しない不毛の地だったら、構わず逃げたでしょうけど……","ENG":"I would have left this place without regret if it was a wasteland with nothing in it,","TWN":"如果這裡是什麼都沒有的無底洞，我大概會毫不猶豫的逃跑……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"사람이 살고 있다는 걸 알고 있는 한, 그걸 무시한 채 떠날 순 없어요.","JPN":"人間がいることを知った以上、見て見ぬふりをして離れるわけにはいきません。","ENG":"but now that I know it's inhabited by people, I can't ignore them.","TWN":"不過既然知道這裡有人活著，那就不能無視他們從這裡逃跑了。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"흐음, 가능성 없는 싸움에 목숨을 던지다니.","JPN":"ふーん、勝算のない戦いに命をかけるなんて。","ENG":"Hm, you want to throw your life away over a losing battle.","TWN":"哦，居然要為這種沒有可能性的戰鬥賭上性命。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"제가 알고 있던 당신은 좀 더 계산적이고 현실주의적이었는데 말이죠.","JPN":"私の知るあなたは、もっと論理的で現実主義だったと思いますが。","ENG":"I thought you were more calculating and realistic than that.","TWN":"據我所知，妳應該是更加精明、更加現實主義的人吧。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"군인은 임무를 위해 언제나 냉철함을 유지해야 합니다.","JPN":"軍人は任務のために、常に冷静さを保つ必要があります。","ENG":"We soldiers must remain coolheaded while on our missions.","TWN":"軍人要執行任務必須時刻保持冷靜。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그리고 제게 주어진 임무는......","JPN":"それに、私に与えられた任務は……","ENG":"And my mission this time...","TWN":"而我的任務……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"방금 전에 성공적으로 완수했어요.","JPN":"ついさっき、無事完遂しました。","ENG":"I successfully accomplished it just now.","TWN":"剛才已經結束了。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"......그뿐입니다.","JPN":"……それだけのことです。","ENG":"I have no regrets.","TWN":"……僅此而已。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"고작 한 사람이 두 세상을 지키기 위해 목숨 바친다, 라......","JPN":"たった一人で、二つの世界を守るために命を捧げる、か……","ENG":"You're just one woman, and you're ready to die fighting for two worlds.","TWN":"至少一個人能為守護兩個世界獻出生命，是嗎……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"저로선 감히 상상도 못할 일이네요.","JPN":"私にはとても想像できませんね。","ENG":"I can't even imagine doing such a thing.","TWN":"我根本無法想像的事情呢。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"혹시 아예 네피림을 쓰러뜨린다는 선택지는 없나요?","JPN":"いっそのこと、ネフィリムを倒すって選択肢はありませんか？","ENG":"Aren't there other options, to bring down the Nephil for example?","TWN":"難道就沒有消滅諾菲力這個選項嗎？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"......네?","JPN":"……え？","ENG":"Excuse me?","TWN":"……什麼？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"아아, 그거 말이군요.","JPN":"ああ、あれのことですね。","ENG":"Oh, that.","TWN":"啊，這個嘛。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그야, 작전 계획에 비슷한 내용이 있기는 했죠.","JPN":"作戦計画の一つに、それに似た計画があるにはありましたね。","ENG":"Well, our original plan included something similar.","TWN":"作戰計畫裡確實有類似的內容。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"건너온 네피림이 아직 이쪽 세계의 위상차에 적응하지 못한 동안 공격하여 틈을 만든 후,","JPN":"やってきたネフィリムが、まだこっち側の位相に適応できてない間を狙って攻撃する、そして隙を見て、","ENG":"Before the Nephil adjusts itself to the phase of this world, we could strike at it, throwing it off balance,","TWN":"趁諾菲力還沒有適應這邊世界的能量差，對它進行攻擊製造破綻，"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"통로가 소멸하기 전에 귀환한다...... 는 이상적인 내용 말이죠.","JPN":"通路が消滅する前に帰還する……という理想的な内容でしたよね。","ENG":"and return through the passageway before it closes. Something idealistic like that.","TWN":"然後在通道關閉之前返回……有這種理想化的內容呢。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"하지만 그건 그냥 죽으러 간다고 하긴 뭣하니까 대충 희망사항을 적은 내용일 뿐입니다.","JPN":"でもあれはただ、「死んで来い」とは言えないから、適当に希望を書いただけです。","ENG":"But that was just wishful thinking, to gloss over the fact that we were on a suicide mission.","TWN":"但這不過是為了掩蓋那低到離譜的生還率，所開出的空頭支票。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"현실성이라곤...... 전혀 없어요.","JPN":"現実味なんて……まるでありません。","ENG":"It's not realistic at all.","TWN":"可行性……完全沒有呢。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"애초에 네피림에게 유의미한 타격을 주는 게 가능했다면 우리가 이런 만행을 저지를 필요도 없었겠죠.","JPN":"そもそもネフィリムに有効な攻撃ができるなら、こんなことする必要もなかったはず。","ENG":"If we could defeat the Nephil, we wouldn't have had to commit this atrocity to begin with.","TWN":"如果當初可以對諾菲力造成有效打擊，我們也沒必要做出這種暴行。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"속여서 미안해요, 시영 씨. 하지만 때로는 포기해야 할 때도 있는 법입니다.","JPN":"ごめんなさい、シノンさん。ですが、時には、諦めるべき時もあるのです。","ENG":"I'm sorry I lied to you, Shiyoung. But sometimes you have no choice but to give up.","TWN":"很抱歉騙了妳，時雨小姐。但有時，我們不得不放棄。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"흐음...... 저도 방금 전까진 비슷한 생각을 하면서 그러려니 했는데 말이죠......","JPN":"ふーん……私もさっきまでは同じようなことを考えていたんですが……","ENG":"Well, I had the same thought","TWN":"哼嗯……剛才為止，我的想法跟妳還是一樣的……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"뜻밖의 변수가 생긴 것 같아서요.","JPN":"思いがけない手練れが現れたみたいで。","ENG":"until the unexpected variables presented themselves.","TWN":"不過似乎發生了點意外。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"변수......?","JPN":"手練れ……？","ENG":"Unexpected variables?","TWN":"意外……？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"어때, 결정은 내렸나?","JPN":"どうだ、決めたのか？","ENG":"So, did you make up your mind?","TWN":"怎麼樣，下定決心了嗎？"},"stage":{"bg":"HANGAR","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"너희가 거들지 않는다고 해도 상관없다. 방해만 하지 않는다면 말이지.","JPN":"お前らに手伝うつもりがなくても構わない。邪魔さえしなければそれでいい。","ENG":"I don't care even if you don't want to help me. Just stay out of my way.","TWN":"你們不幫忙也無所謂。只要別礙事就行。"},"stage":{"bg":"HANGAR","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"뭐, 뭐죠, 저 사람들은? 주시영 씨 당신이 데려온 건가요?","JPN":"だ、誰です、あの連中は？　シノンさんが連れてきたんですか？","ENG":"W-who are those people? Shiyoung, did you bring them with you?","TWN":"什、什麼，那些人是誰啊？是時雨小姐妳帶過來的嗎？"},"stage":{"bg":"HANGAR","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"데려왔다기보다는 제가 끌려왔다는 게 정확한 표현이겠네요.","JPN":"私が連れてきたというより、むしろその逆でしょうね。","ENG":"I didn't bring them; they dragged me here, more like.","TWN":"與其說我帶來的，不如說我才是被他們抓過來的。"},"stage":{"bg":"HANGAR","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"}}}},{"id":"L42_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"저분들이 함께 네피림을 사냥하지 않겠냐고 제안하셨거든요.","JPN":"あの方たちに、一緒にネフィリム狩りをしないかと誘われたんです。","ENG":"They suggested we hunt the Nephil together.","TWN":"他們向我提議要不要一起狩獵諾菲力來著。"},"stage":{"bg":"HANGAR","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"사냥?","JPN":"ネフィリム狩り？","ENG":"Hunt the Nephil?","TWN":"狩獵？"},"stage":{"bg":"HANGAR","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"무슨 생각인지는 모르겠지만 네피림과 싸우겠다는 건 자살행위입니다!","JPN":"どういうつもりかわかりませんが、ネフィリムと戦うのは自殺行為です！","ENG":"I don't know what you think you can do, but fighting the Nephil is suicidal.","TWN":"雖然不知道你們在想什麼，但和諾菲力戰鬥無異於自殺！"},"stage":{"bg":"HANGAR","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"끌고 온 우리가 할 말은 아니지만...... 네피림이라고 하루 아침에 세상을 멸망시킬 수 있는 건 아니에요.","JPN":"連れてきた私たちが言うのもなんですが、いくらネフィリムでもすぐに世界を滅ぼすことはできません。","ENG":"This may not be the most appropriate thing I can say, seeing we've lured it to your world, but even the Nephil can't destroy a world overnight.","TWN":"雖然把諾菲力拉過來的我們沒什麼資格這麼說……但諾菲力並不會在一天內就把世界毀滅掉。"},"stage":{"bg":"HANGAR","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그러니까...... 차라리 도망쳐서 조금이라도 더 오래 살아남는 편이 나을 겁니다.","JPN":"ですから……なんとか逃げて、少しでも生き延びたほうが賢明だと思います。","ENG":"So, you should run now and try to preserve yourselves for as long as you can.","TWN":"所以……你們還不如能跑多遠跑多遠，能活一天是一天。"},"stage":{"bg":"HANGAR","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"정말 희망이 없다면 그것도 나쁘지 않은 선택이겠죠.","JPN":"希望がまったくないなら、それも悪くはないでしょうね。","ENG":"If there really is no hope, that wouldn't be too bad an idea.","TWN":"如果毫無希望，這種選擇也不差吧。"},"stage":{"bg":"HANGAR","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하지만 이번엔, 당신이 말하는 이상론에 한 번 걸어보는 게 어떨까요?","JPN":"ですが今回は、あなたの言う理想論に賭けてみませんか？","ENG":"But why don't you bet on that idealistic part of your plan this time?","TWN":"不過這次，為什麼不試試妳說的理想化內容呢？"},"stage":{"bg":"HANGAR","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"당신은?!","JPN":"あなたは！？　","ENG":"You...","TWN":"你？！"},"stage":{"bg":"HANGAR","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하하, 이거 실례했군요. 제 이름은......","JPN":"ハハ、これは失礼しました。僕の名前は……","ENG":"Ah, where are my manners? My name is...","TWN":"哈哈，真是失禮了。我的名字是……"},"stage":{"bg":"HANGAR","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"시영 씨랑 판박이잖아!!","JPN":"シノンさんと瓜二つじゃないですか！！","ENG":"You look just like Shiyoung!","TWN":"你和時雨一模一樣！！"},"stage":{"bg":"HANGAR","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"주시윤입니다......","JPN":"アキヤマ・シリュウです……","ENG":"... Joo Shiyoon.","TWN":"周時雲……"},"stage":{"bg":"HANGAR","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"한 명으로 모자라서 두 명으로 분열하다니, 절 어디까지 고생시킬 속셈인가요!","JPN":"一人でも手に負えないというのに、二人に分裂するなんて、私をどこまで困らせるつもりですか！","ENG":"I can barely handle one of you, let alone two. What have I done to deserve this?","TWN":"一個不夠竟然分裂成兩個，到底是多想把我折磨到死啊！"},"stage":{"bg":"HANGAR","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"편두통이...... 두 배로 오는 것 같아......","JPN":"いつもの偏頭痛が……倍になりそう……","ENG":"I feel like I'm getting a double headache…","TWN":"頭痛……好像要變成兩倍痛了……"},"stage":{"bg":"HANGAR","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하하, 두 분이 어떤 사이인지 대충 알 것 같아서 더 섭섭해지네요.","JPN":"ハハ、二人の関係性が読めてしまって、悲しくなっちゃいますね。","ENG":"Hah hah. So, that's how you think of her. I'm disappointed. All the more so than before.","TWN":"哈哈，我大概能猜到兩位是什麼關係了，有點更寂寞了呢。"},"stage":{"bg":"HANGAR","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그래도 지금은 방금 말이 나온 이상론으로 돌아가 보죠.","JPN":"それでも、今はさっきの理想論に戻ってみましょう。","ENG":"But let's go back to that idealistic part of your plan, shall we?","TWN":"那麼話題回到剛才說的理想化內容。"},"stage":{"bg":"HANGAR","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"......?","JPN":"……？","ENG":"......?","TWN":"……"},"stage":{"bg":"HANGAR","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"이곳엔 <color=#ffd34c>관리국</color>이라는 조직이 있습니다.","JPN":"ここには<color=#ffd34c>管理局</color>という組織があります。","ENG":"Here, there's an organization called the <color=#ffd34c>Administration</color>.","TWN":"這邊有個叫 <color=#ffd34c>管理局</color>的組織。"},"stage":{"bg":"HANGAR","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"처음에는 우리 세계도 고위 침식체의 공격에 속수무책이었지만......","JPN":"最初は僕たちの世界も、高位侵食体からの攻撃に成す術がなかったのですが……","ENG":"At first, our world was just as helpless as yours to the attacks of high-ranking Corrupted Objects,","TWN":"一開始我們的世界也因高等侵蝕體攻擊而束手無策……"},"stage":{"bg":"HANGAR","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"관리국의 도움으로 이제는 그럭저럭 대응을 할 수 있게 됐죠.","JPN":"管理局からの支援のおかげで、今はなんとか対応できるようになりました。","ENG":"until the Administration showed up and got a handle on things.","TWN":"不過在管理局的幫助下，現在總算是可以應付了。"},"stage":{"bg":"HANGAR","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"관리국......? 그럼 제가 본 기술 격차도......?","JPN":"管理局……？　じゃあ、私が見た技術の格差も、そこから……？","ENG":"The Administration? Then, the technological superiority that I've witnessed...","TWN":"管理局……？那麼我看到的技術差距也是……？"},"stage":{"bg":"HANGAR","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"네. 관리국의 유무로 생긴 차이겠죠.","JPN":"はい、管理局の存在によってできた格差でしょうね。","ENG":"Yes, that probably also has to do with the Administration.","TWN":"是的，那就是有沒有管理局的差距。"},"stage":{"bg":"HANGAR","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"오면서 시영 씨 얘기를 들었는데, 그쪽 세계는 여기보다 이터니움 공학이 많이 뒤떨어진 것 같더군요.","JPN":"来る途中でシノンさんから聞いたのですが、そちらの世界はこの世界と比べ、エタニウム工学が遅れをとっているようでした。","ENG":"Shiyoung and I talked on our way here, and I've gathered that Eternium engineering isn't as advanced in your world as it is in ours.","TWN":"來的時候聽時雨小姐說，那邊世界的永恆之金工學似乎比這裡落後許多。"},"stage":{"bg":"HANGAR","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"관리국이 제공하는 대 침식전 전용장비를 잘 활용하기만 하면,","JPN":"管理局から提供される侵食戦専用装備をうまく活用さえすれば、","ENG":"We've got anti-Corruption gear from the Administration.","TWN":"只要能好好使用管理局提供的對侵蝕戰專用裝備……"},"stage":{"bg":"HANGAR","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그 <color=#ffd34c>네피림</color>이라는 침식체 정도는 충분히 상대할 수 있을 겁니다.","JPN":"その<color=#ffd34c>ネフィリム</color>という侵食体くらいは十分相手できると思います。","ENG":"With it, we should be able to take care of that C.O. named the <color=#ffd34c>Nephil</color> without problem.","TWN":"應該足以應付那個叫 <color=#ffd34c>諾菲力</color>的侵蝕體。"},"stage":{"bg":"HANGAR","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그, 그런......","JPN":"そ、そんな……","ENG":"Th-that's...","TWN":"這、這……"},"stage":{"bg":"HANGAR","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그럴 리가...... 그런 꿈 같은 일이 사실이라고요?","JPN":"そんなはずは……そんな夢のようなことが、事実だというのですか？","ENG":"That sounds... surreal. Are you sure?","TWN":"怎麼可能……難道我在做夢嗎？"},"stage":{"bg":"HANGAR","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"믿지 못하겠다면 직접 눈으로 보는 게 제일이겠죠.","JPN":"信じられないなら、自分の目で確かめるのが一番です。","ENG":"If you don't believe me, then you can see it for yourself.","TWN":"如果妳沒辦法相信，就親眼看一看吧。"},"stage":{"bg":"HANGAR","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"마침 클리포트 인자에 이끌린 제 3종 침식체들이 통로 주변에 나타나는 것 같네요.","JPN":"ちょうどクリフォト・ファクターに引き寄せられた第3種侵食体が通路周辺に現れているようです。","ENG":"Some Category 3 C.O.s have appeared near the passageway, following the Qliphoth Factor.","TWN":"剛好有被逆卡巴拉因子吸引的3級侵蝕體出現在通道周圍。"},"stage":{"bg":"HANGAR","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"샘플로 보여 드리기에 딱 알맞겠어요.","JPN":"お手本を見せるには、もってこいですね。","ENG":"Good, I can use them for a demonstration.","TWN":"正好可以當樣本讓妳見識一下。"},"stage":{"bg":"HANGAR","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};